atural_treasure_count_visited":3,"bomun_lake_apec_2025_anchor":true,"differentiates_from_plum_cherry_blossom_route":true,"first_time_gyeongju_fit":1,"kid_friendly_fit":0.9,"deep_history_traveler_fit_minimum":0.7,"english_speaking_guide_provided":true,"chinese_speaking_guide_available_on_advance_notice":true,"japanese_speaking_guide_available_on_advance_notice":true},"matching_metadata":{"competing_products":["busan-plum-cherry-blossom-day-tour-to-yangsan-gyeongju","busan-gyeongju-unesco-legacy-tour-national-museum","from-busan-gyeongju-ancient-capital-day-tour"],"complementary_products":["busan-top-attractions-day-tour","busan-small-group-sightseeing-tour-cruise-passengers"],"upgrade_from":[],"downgrade_to":["busan-gyeongju-unesco-legacy-tour-national-museum"],"internal_competing_products_note":"Within the Busan→Gyeongju portfolio, this is the SEASONAL spring-only cherry blossom variant. The two year-round Gyeongju tours (busan-gyeongju-unesco-legacy-tour-national-museum, from-busan-gyeongju-ancient-capital-day-tour) cover the same UNESCO core (Bulguksa + Gyeongju historic area) but skip the cherry blossom POIs (Bomun Lake, Cheomseongdae fields, Stone Wall Road). For visits outside Mar 28–Apr 10 the year-round tours are the substitute.","external_source":"GetYourGuide t1192332","external_source_url":"https://www.getyourguide.com/-t1192332/","operator_partner":"AtoC Korea LLC (seasonal cherry blossom shuttle)","last_competitive_review":"2026-04-28","primary_themes":["unesco","silla_kingdom","cherry_blossom","buddhist_temple"],"secondary_themes":["tomb_complex","astronomical_heritage","lake","spring_festival"],"best_for":["first_time_visitors","culture_lovers","couples","spring_seasonal_travelers","history_enthusiasts","photographers"],"not_recommended_for":["shoppers_only","nightlife_seekers","bad_weather_intolerant"],"anchor_pois":["Bomun Lake","Cheomseongdae Observatory + Daereungwon Tomb Complex","Bulguksa Temple"],"anchor_poi_keys":["bomun_lake","cheomseongdae","daereungwon_tomb_complex","bulguksa_temple"],"enrichment_batch":"17a","enrichment_date":"2026-04-29","enrichment_kb_version":"1.23","enrichment_target_kb_version":"1.24","profile_version_pre":6,"profile_version_post":6,"schema_version":7,"patch_type":"polish_existing_pv6_to_a_grade","patch_target":"16 substantive stops across 4 tours; D-grade audit (8-hl-vs-9-hl artifact) → A-grade pass"},"itinerary_variants":[],"_publication":{"schema_version":"v4_canonical","last_modified":"2026-04-28","version_history":["v15.4_new_tour_creation"],"fix_passes":{"v15.4_new_tour_creation":"Created new tour from GYG product ID t1192332 (Busan-Gyeongju spring cherry blossom day tour). Structural template: busan-gyeongju-unesco-legacy-tour-national-museum (same Busan→Gyeongju logistics, shuttle small_group format). Content layered with cherry-blossom-specific POIs added to KB v1.1: bomun_lake, daereungwon_tomb_complex, cheomseongdae. POI operational data sourced from VisitKorea, Visit Busan, Gyeongju City tourism office, Trazy listings, KoreaTravelEasy, Seoul Pass listings (cross-verified across 4–6 sources per POI). SEASONALITY is STRICT: spring=1.0, summer/autumn/winter=0.0 — tour operates only Mar 28–Apr 10 (verified from GYG t1192332 dating and Trazy listings 2024–2026). MATCHING-PROFILE SCORING METHODOLOGY: All 68 fields scored from verified facts about the actual stops in the default itinerary (walking distances measured, accessibility per VisitKorea + AllTrails, hours/admission per official tourism boards, UNESCO designations per UNESCO World Heritage List). Inline reasoning for each non-trivial score is captured as comments in the generator script step3b_create_cherry_blossom_tour.py — Jason can review or adjust any specific score by editing the generator and re-running. Key derivations: (1) walking_level=0.50 from measured 3–5km total walking with mostly flat paths and one stair section; (2) unesco_fit=0.95 from 3-of-4 stops being UNESCO-listed; (3) seasonality.spring=1.0 + others=0.0 from verified seasonal-only operating dates; (4) couple_fit=0.95 vs young_kids_fit=0.50 from cherry blossom romance vs 8.5h day length tradeoff; (5) value_for_money_fit=0.85 from 4 free admissions + shuttle pricing in peak demand season. REASONABLE-ASSUMPTION FIELDS that may need patching once the live GYG page is reviewed: (a) price.amountLabel left empty (per-person pricing TBD); (b) catalog_card.priceFromUSD null; (c) exact pickup times (08:00/08:15/08:30) assumed from typical shuttle schedule; (d) reviewsSummary populated with zeros — actual GYG reviews not imported in this pass; (e) hero/og images deferred per v15 P3 image workflow.","v17_schema_unification":{"date":"2026-04-28","description":"Phase 1: Converted matching_profile scores from 1-5 int scale to 0-1 float scale to match the 3 Step 3 new tours. Mapping 1→0.20, 2→0.40, 3→0.60, 4→0.80, 5→1.00. Mechanical conversion preserves ordinal information; verified-fact recalibration happens in subsequent enhancement batches.","fields_converted":0,"fields_skipped":0,"fields_already_float":42}}}}'::jsonb
